  1→import { fixtureOutline } from '@/geometry/fixtureGeometry';
  2→
  3→const FIXTURE_FILLS = {
  4→  kitchenTop: '#E8D5B7',
  5→  toilet: '#D4E8F0',
  6→  lavatory: '#D4E8F0',
  7→  table: '#E0D4C0',
  8→  tv: '#333',
  9→  sofa: '#C8B8A8',
 10→};
 11→
 12→function FixtureDetails({ fixture }) {
 13→  const { fixtureType, x, y, width, depth, rotation } = fixture;
 14→  const hw = width / 2, hd = depth / 2;
 15→
 16→  // Render type-specific SVG internal details inside a rotated group
 17→  const transform = `translate(${x},${y}) rotate(${rotation || 0})`;
 18→
 19→  switch (fixtureType) {
 20→    case 'kitchenTop':
 21→      return (
 22→        <g transform={transform}>
 23→          {/* Burner circles */}
 24→          <circle cx={-hw + width * 0.2} cy={0} r={depth * 0.15} fill="none" stroke="#888" strokeWidth={1} vectorEffect="non-scaling-stroke" />
 25→          <circle cx={-hw + width * 0.4} cy={0} r={depth * 0.15} fill="none" stroke="#888" strokeWidth={1} vectorEffect="non-scaling-stroke" />
 26→          {/* Sink rectangle */}
 27→          <rect x={hw - width * 0.3} y={-hd * 0.6} width={width * 0.2} height={depth * 0.6} rx={2} fill="none" stroke="#888" strokeWidth={1} vectorEffect="non-scaling-stroke" />
 28→        </g>
 29→      );
 30→    case 'toilet':
 31→      return (
 32→        <g transform={transform}>
 33→          {/* Cistern rectangle */}
 34→          <rect x={-hw} y={-hd} width={width} height={depth * 0.35} rx={2} fill="none" stroke="#888" strokeWidth={1} vectorEffect="non-scaling-stroke" />
 35→          {/* Bowl oval */}
 36→          <ellipse cx={0} cy={hd * 0.3} rx={width * 0.35} ry={depth * 0.35} fill="none" stroke="#888" strokeWidth={1} vectorEffect="non-scaling-stroke" />
 37→        </g>
 38→      );
 39→    case 'lavatory':
 40→      return (
 41→        <g transform={transform}>
 42→          {/* Basin circle */}
 43→          <circle cx={0} cy={0} r={Math.min(width, depth) * 0.3} fill="none" stroke="#888" strokeWidth={1} vectorEffect="non-scaling-stroke" />
 44→        </g>
 45→      );
 46→    case 'table':
 47→      return (
 48→        <g transform={transform}>
 49→          {/* Corner leg indicators */}
 50→          <circle cx={-hw + width * 0.1} cy={-hd + depth * 0.1} r={width * 0.03} fill="#888" stroke="none" />
 51→          <circle cx={hw - width * 0.1} cy={-hd + depth * 0.1} r={width * 0.03} fill="#888" stroke="none" />
 52→          <circle cx={-hw + width * 0.1} cy={hd - depth * 0.1} r={width * 0.03} fill="#888" stroke="none" />
 53→          <circle cx={hw - width * 0.1} cy={hd - depth * 0.1} r={width * 0.03} fill="#888" stroke="none" />
 54→        </g>
 55→      );
 56→    case 'tv':
 57→      return (
 58→        <g transform={transform}>
 59→          {/* Stand */}
 60→          <line x1={-width * 0.15} y1={hd} x2={width * 0.15} y2={hd} stroke="#888" strokeWidth={1} vectorEffect="non-scaling-stroke" />
 61→        </g>
 62→      );
 63→    case 'sofa':
 64→      return (
 65→        <g transform={transform}>
 66→          {/* Backrest line */}
 67→          <line x1={-hw + width * 0.05} y1={-hd + depth * 0.25} x2={hw - width * 0.05} y2={-hd + depth * 0.25} stroke="#888" strokeWidth={1} vectorEffect="non-scaling-stroke" />
 68→          {/* Armrests */}
 69→          <line x1={-hw + width * 0.08} y1={-hd + depth * 0.25} x2={-hw + width * 0.08} y2={hd - depth * 0.1} stroke="#888" strokeWidth={1} vectorEffect="non-scaling-stroke" />
 70→          <line x1={hw - width * 0.08} y1={-hd + depth * 0.25} x2={hw - width * 0.08} y2={hd - depth * 0.1} stroke="#888" strokeWidth={1} vectorEffect="non-scaling-stroke" />
 71→        </g>
 72→      );
 73→    default:
 74→      return null;
 75→  }
 76→}
 77→
 78→export default function FixtureRenderer({ fixtures }) {
 79→  return (
 80→    <g className="fixtures">
 81→      {fixtures.map(fixture => {
 82→        const outline = fixtureOutline(fixture);
 83→        const points = outline.map(p => `${p.x},${p.y}`).join(' ');
 84→        const fill = FIXTURE_FILLS[fixture.fixtureType] || '#DDD';
 85→        return (
 86→          <g key={fixture.id}>
 87→            <polygon
 88→              data-id={fixture.id}
 89→              data-type="fixture"
 90→              points={points}
 91→              fill={fill}
 92→              stroke="#666"
 93→              strokeWidth={1}
 94→              vectorEffect="non-scaling-stroke"
 95→            />
 96→            <FixtureDetails fixture={fixture} />
 97→          </g>
 98→        );
 99→      })}
100→    </g>
101→  );
102→}
